{
  "intent": "check_and_fix",
  "intent_description": "BGP adjacency on R3 is down and R3 is unreachable by the management/collection system; likely causes: R3 management-plane failure or loss of IP adjacency on the R2–R3 link. Desired outcome: collect missing diagnostics to confirm root cause and restore BGP by repairing management access or the R2–R3 adjacency.",
  "target": "R3",
  "needs_fix": true,
  "plan": {
    "problem": "BGP not established on router3; management-plane collection failed for router3 and OSPF shows missing neighbor on R2 Serial0/1/1 (possible R2–R3 adjacency loss).",
    "fix_summary": "Collect missing state from R3 and R2 to confirm whether R3 is unreachable or the R2–R3 IP adjacency is down; then restore management access or repair the R2–R3 interface/IP adjacency as required.",
    "plan_steps": [
      {
        "id": 1,
        "device": "router3",
        "action": "get_running_config",
        "target": "section router bgp",
        "parameters": [
          "filter=section router bgp"
        ]
      },
      {
        "id": 2,
        "device": "router3",
        "action": "get_bgp_summary",
        "target": null,
        "parameters": []
      },
      {
        "id": 3,
        "device": "router3",
        "action": "get_ip_interface_brief",
        "target": null,
        "parameters": []
      },
      {
        "id": 4,
        "device": "router2",
        "action": "get_ospf",
        "target": "Serial0/1/1",
        "parameters": [
          "show=neighbors"
        ]
      },
      {
        "id": 5,
        "device": "router2",
        "action": "get_interface",
        "target": "Serial0/1/1",
        "parameters": [
          "show=ip,admin,protocol"
        ]
      }
    ]
  }
}

